import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { EventItem, Venue } from '../../core/models';

/**
 * GatherUp organizer dashboard — lists the organizer's events with confirmed /
 * capacity, links to the per-event attendee page, and offers an inline
 * create-event form. Loads live via ApiService.listEvents()/listVenues();
 * the form submits through ApiService.createEvent().
 */
@Component({
  selector: 'app-organizer-dashboard',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './organizer-dashboard.component.html',
  styleUrl: './organizer-dashboard.component.css',
})
export class OrganizerDashboardComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly showForm = signal(false);

  readonly events = signal<EventItem[]>([]);

  readonly venues = signal<Venue[]>([]);

  readonly totalConfirmed = computed(() =>
    this.events().reduce((s, e) => s + (e.confirmedCount ?? 0), 0),
  );
  readonly totalWaitlist = computed(() =>
    this.events().reduce((s, e) => s + (e.waitlistCount ?? 0), 0),
  );

  // New-event form model.
  form = { title: '', category: '', venueId: '', startsAt: '', endsAt: '', capacity: 50, description: '' };
  readonly formError = signal<string | null>(null);

  constructor(private api: ApiService) {}

  ngOnInit(): void {
    this.loadEvents();
    this.api.listVenues().subscribe({
      next: (venues) => this.venues.set(venues),
      error: () => {},
    });
  }

  private loadEvents(): void {
    this.loading.set(true);
    this.error.set(null);
    this.api.listEvents().subscribe({
      next: (events) => {
        this.events.set(events);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load events. Please try again.');
        this.loading.set(false);
      },
    });
  }

  toggleForm(): void {
    this.showForm.update((v) => !v);
    this.formError.set(null);
  }

  createEvent(): void {
    if (!this.form.title || !this.form.venueId || !this.form.startsAt) {
      this.formError.set('Title, venue and start time are required.');
      return;
    }
    // Convert datetime-local values to ISO-8601 (the backend DTO uses @IsDateString).
    const startsAt = new Date(this.form.startsAt).toISOString();
    const endsAt = new Date(this.form.endsAt || this.form.startsAt).toISOString();
    const payload: Partial<EventItem> = {
      venueId: this.form.venueId,
      title: this.form.title,
      description: this.form.description,
      category: this.form.category || 'General',
      startsAt,
      endsAt,
      capacity: Number(this.form.capacity) || 1,
    };
    this.formError.set(null);
    this.api.createEvent(payload).subscribe({
      next: () => {
        this.form = { title: '', category: '', venueId: '', startsAt: '', endsAt: '', capacity: 50, description: '' };
        this.showForm.set(false);
        this.loadEvents();
      },
      error: () => this.formError.set('Could not create the event. Check the details and try again.'),
    });
  }

  spotsLabel(e: EventItem): string {
    const left = Math.max(0, e.capacity - (e.confirmedCount ?? 0));
    return left > 0 ? `${left} spots left` : 'Full';
  }

  when(iso: string): string {
    return new Date(iso).toLocaleString(undefined, {
      month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit',
    });
  }
}
